parameters.jsCode:
const items = $input.all();
const wf = $('Ejecutar Workflow').first().json;
const busqueda = (wf.busqueda ?? '').trim();
const filtroStatus = (wf.filtro_status ?? '').trim();
const filtroTipo = (wf.filtro_tipo ?? '').trim();

// Detect empty rows (postgres node outputs 1 empty item when 0 results)
const props = (items.length === 1 && Object.keys(items[0].json).length === 0) ? [] : items;

if (props.length === 0) {
  const contexto = busqueda ? `para "${busqueda}"` : (filtroStatus || filtroTipo ? 'con los filtros indicados' : 'en la base de datos');
  return [{ json: { id: null, resultado: `🔍 No se encontró ningún inmueble activo ${contexto}.` } }];
}

if (props.length === 1) {
  // Single result: return full detail
  return [{ json: { ...props[0].json, resultado: null } }];
}

// Multiple results: build list
const lista = props.map((it, i) => {
  const p = it.json;
  const precio = p.price ? ' ($' + Number(p.price).toLocaleString('es-EC') + ')' : '';
  return `${i + 1}. *${p.code}* - ${p.property_type} en ${p.address}${precio} | Estado: ${p.status}`;
}).join('\n');

const titulo = busqueda
  ? `🏠 Encontré ${props.length} inmuebles para "${busqueda}":`
  : `🏠 Lista de inmuebles (${props.length} en total):`;

return [{
  json: {
    id: null,
    resultado: `${titulo}\n\n${lista}\n\n👉 Indícame el código exacto para ver todos los detalles (ej: 001, 002).`
  }
}];

